UIDressStoreTip = class("DressStoreLackMoneyTip", IGUILayout)

local lackMoney = 0
local DressId = 0

function UIDressStoreTip:onLoad()
    self.stTip = self:getChildWindow("DressStoreTip-BedWar-Title-Name", GUIType.StaticText)
    self.stMassage = self:getChildWindow("DressStoreTip-BedWar-Content-Vehicle-Message", GUIType.StaticText)
    self.stValue = self:getChildWindow("DressStoreTip-BedWar-Content-Currency-Value", GUIType.StaticText)
    self.siIcon = self:getChildWindow("DressStoreTip-BedWar-Content-Currency-Icon", GUIType.StaticImage)
    self.btnCancel = self:getChildWindow("DressStoreTip-BedWar-Btn-Cancel", GUIType.Button)
    self.btnSure = self:getChildWindow("DressStoreTip-BedWar-Btn-Sure", GUIType.Button)
    self.btnClose = self:getChildWindow("DressStoreTip-Close", GUIType.Button)
    self.stTip:SetText(Lang:getString("gui_dialog_tip_title_tip"))
    self.btnCancel:SetText(Lang:getString("gui_dialog_tip_btn_cancel"))
    self.btnSure:SetText(Lang:getString("gui_dialog_tip_btn_sure"))
    self:register()
end

function UIDressStoreTip:updateLanguage()

end

function UIDressStoreTip:register()
    self.btnCancel:registerEvent(GUIEvent.ButtonClick, function()
        GUIDressStoreTip:hide()
    end)

    self.btnClose:registerEvent(GUIEvent.ButtonClick, function()
        GUIDressStoreTip:hide()
    end)

    self.btnSure:registerEvent(GUIEvent.ButtonClick, function()
        if self.flag == "LockTip" then
            GUIDressStoreTip:hide()
        elseif self.flag == "LackChip" then
            PayHelper.checkMoney(5, lackMoney * 2, function(isEnough)
                if isEnough then
                    GUIDressStoreTip:hide()
                    GamePacketSender:sendLackChipTipResult(DressId)
                    UIDressStore:changeStatue(DressId, 5)
                else
                    RootGuiLayout.Instance():showMainControl()
                    GUIStore:show(StoreId.CubeStore, 8)
                end
            end)
            CustomDialog.hide()
            CustomDialog.setCloseVisible(false)
        end
    end)
end

function UIDressStoreTip:setLackChipText(lackNum, lackChip, Id)
    DressId = Id
    lackMoney = lackNum
    self.flag = "LackChip"
    local string = Lang:getString(lackChip)
    local tip = string.format(Lang:getString("lack_dress_chip_by_key"), lackNum, string)
    self.stMassage:SetText(tip)
    self.stValue:SetText(lackNum * 2)
end

function UIDressStoreTip:setLockTip(lockLevel)
    self.stValue:SetVisible(false)
    self.siIcon:SetVisible(false)
    self.flag = "LockTip"
    local tip = string.format(Lang:getString("DressSetting_unlock"), lockLevel)
    self.stMassage:SetText(tip)
end

return UIDressStoreTip